import hashlib
import time
import threading
from collections import defaultdict
import uuid

class EngagementMonitor:
    def __init__(self, anonymize_user_ids=True):
        self.engagements = defaultdict(lambda: defaultdict(list))  # {engagement_type: {anonymized_user_id: [timestamp1, timestamp2, ...]}}
        self.user_id_map = {}  # {user_id: anonymized_user_id}
        self.lock = threading.Lock()
        self.anonymize_user_ids = anonymize_user_ids

    def anonymize_user_id(self, user_id):
        """
        Anonymizes a user ID using SHA-256 hashing.
        """
        user_id_str = str(user_id).encode('utf-8')
        return hashlib.sha256(user_id_str).hexdigest()

    def get_anonymized_id(self, user_id):
        """
        Returns the anonymized ID for a user, creating one if it doesn't exist.
        """
        with self.lock:
            if user_id not in self.user_id_map:
                self.user_id_map[user_id] = self.anonymize_user_id(user_id)
            return self.user_id_map[user_id]

    def record_engagement(self, user_id, engagement_type):
        """
        Records a user engagement.
        """
        if self.anonymize_user_ids:
            anonymized_user_id = self.get_anonymized_id(user_id)
        else:
            anonymized_user_id = user_id

        timestamp = time.time()

        with self.lock:
            self.engagements[engagement_type][anonymized_user_id].append(timestamp)

    def get_user_engagements(self, user_id, engagement_type=None):
        """
        Retrieves a user's engagements, optionally filtered by engagement type.
        """
        if self.anonymize_user_ids:
            try:
                anonymized_user_id = self.user_id_map[user_id]
            except KeyError:
                return {} # User has no recorded engagements
        else:
            anonymized_user_id = user_id

        with self.lock:
            if engagement_type:
                return {engagement_type: self.engagements.get(engagement_type, {}).get(anonymized_user_id, [])}
            else:
                user_engagements = {}
                for eng_type, user_data in self.engagements.items():
                    if anonymized_user_id in user_data:
                        user_engagements[eng_type] = user_data[anonymized_user_id]
                return user_engagements

    def get_engagement_counts(self, engagement_type):
        """
        Returns the number of engagements for a given type.
        """
        with self.lock:
            return sum(len(engagements) for engagements in self.engagements[engagement_type].values())

    def clear_user_data(self, user_id):
        """
        Clears all engagement data for a given user.
        """
        if self.anonymize_user_ids:
            try:
                anonymized_user_id = self.user_id_map[user_id]
            except KeyError:
                return # User not found
        else:
            anonymized_user_id = user_id

        with self.lock:
            for engagement_type in self.engagements:
                if anonymized_user_id in self.engagements[engagement_type]:
                    del self.engagements[engagement_type][anonymized_user_id]
            if user_id in self.user_id_map:
                del self.user_id_map[user_id]

    def generate_pseudonymous_id(self):
        """
        Generates a pseudonymous ID for a user.  This is different from anonymization,
        as it allows for tracking a user's activity across sessions without revealing
        their actual ID.
        """
        return str(uuid.uuid4())

    def record_engagement_pseudonymous(self, pseudonymous_id, engagement_type):
        """
        Records a user engagement using a pseudonymous ID.
        """
        timestamp = time.time()

        with self.lock:
            self.engagements[engagement_type][pseudonymous_id].append(timestamp)

    def get_engagements_pseudonymous(self, pseudonymous_id, engagement_type=None):
        """
        Retrieves engagements for a given pseudonymous ID.
        """
        with self.lock:
            if engagement_type:
                return {engagement_type: self.engagements.get(engagement_type, {}).get(pseudonymous_id, [])}
