                for eng_type, user_data in self.engagements.items():
                    if pseudonymous_id in user_data:
                        user_engagements[eng_type] = user_data[pseudonymous_id]
                return user_engagements

    def clear_pseudonymous_data(self, pseudonymous_id):
        """
        Clears all engagement data for a given pseudonymous ID.
        """
        with self.lock:
            for engagement_type in self.engagements:
                if pseudonymous_id in self.engagements[engagement_type]:
                    del self.engagements[engagement_type][pseudonymous_id]

