        timestamp = time.time()
        like_data = {
            "timestamp": timestamp,
            "type": "like",
            "item_id": self._anonymize_data(activity_data.get("item_id", None)) if activity_data else None,
        }
        self._store_activity(user_id_hash, like_data)

