        """Logs a 'score' activity."""
        timestamp = time.time()
        score_data = {
            "timestamp": timestamp,
            "type": "score",
            "score_value": activity_data.get("score", None) if activity_data else None,
            "item_id": self._anonymize_data(activity_data.get("item_id", None)) if activity_data else None,
        }
        self._store_activity(user_id_hash, score_data)

