        """Logs an 'upload' activity."""
        timestamp = time.time()
        upload_data = {
            "timestamp": timestamp,
            "type": "upload",
            "file_type": activity_data.get("file_type", None) if activity_data else None,
            "file_size": activity_data.get("file_size", None) if activity_data else None,
        }
        self._store_activity(user_id_hash, upload_data)

