        preference_data = {
            "timestamp": timestamp,
            "type": "preference_update",
            "preference_category": activity_data.get("category", None) if activity_data else None,
            "preference_value": self._anonymize_data(activity_data.get("value", None)) if activity_data else None,
        }
        self._store_activity(user_id_hash, preference_data)

